    private void extractZipAsset(String assetName, File destination) throws IOException {
        String root = destination.getCanonicalPath() + File.separator;
        try (InputStream asset = getAssets().open(assetName);
                ZipInputStream zip = new ZipInputStream(asset)) {
            ZipEntry entry;
            byte[] buffer = new byte[64 * 1024];
            while ((entry = zip.getNextEntry()) != null) {
                File output = new File(destination, entry.getName()).getCanonicalFile();
                if (!output.getPath().startsWith(root)) {
                    throw new IOException("data archive path escapes runtime root");
                }
                if (entry.isDirectory()) {
                    output.mkdirs();
                    continue;
                }
                File parent = output.getParentFile();
                if (parent != null) {
                    parent.mkdirs();
                }
                try (OutputStream file = new FileOutputStream(output)) {
                    int read;
                    while ((read = zip.read(buffer)) != -1) {
                        file.write(buffer, 0, read);
                    }
                }
            }
        }
    }

