        private void commitSubsurfaceBuffer(SubsurfaceState subsurface, int subsurfaceBufferId) throws Exception {
            ShmBufferState buffer = shmBuffers.get(subsurfaceBufferId);
            if (buffer == null) {
                throw new IllegalStateException("subsurface commit with unknown wl_buffer " + subsurfaceBufferId);
            }
            long required = (long) buffer.offset + (long) buffer.stride * buffer.height;
            if (buffer.width <= 0 || buffer.height <= 0 || buffer.stride < buffer.width * 4
                    || required > buffer.pool.size) {
                throw new IllegalStateException("invalid subsurface buffer state before commit");
            }
            byte[] rgba = readExactFromFd(buffer.pool.fd, buffer.offset, buffer.stride * buffer.height);
            int[] argb = new int[buffer.width * buffer.height];
            for (int y = 0; y < buffer.height; y++) {
                int row = y * buffer.stride;
                for (int x = 0; x < buffer.width; x++) {
                    int p = row + x * 4;
                    int b = rgba[p] & 0xff;
                    int g = rgba[p + 1] & 0xff;
                    int r = rgba[p + 2] & 0xff;
                    int a = buffer.format == 0 ? rgba[p + 3] & 0xff : 0xff;
                    argb[y * buffer.width + x] = (a << 24) | (r << 16) | (g << 8) | b;
                }
            }
            subsurface.bitmap = Bitmap.createBitmap(argb, buffer.width, buffer.height, Bitmap.Config.ARGB_8888);
            subsurface.visible = true;
            composeSurfaceTree();
        }

