        private void composeSurfaceTree() {
            Bitmap base = mainBitmap;
            if (base == null) {
                return;
            }
            int originX = presentationOriginX();
            int originY = presentationOriginY();
            WindowGeometry geometry = windowGeometries.get(xdgSurfaceId);
            int scale = Math.max(1, surfaceBufferScales.getOrDefault(surfaceId, 1));
            int cropWidth = geometry == null ? base.getWidth()
                    : Math.min(base.getWidth() - originX, geometry.width * scale);
            int cropHeight = geometry == null ? base.getHeight()
                    : Math.min(base.getHeight() - originY, geometry.height * scale);
            Bitmap composed = Bitmap.createBitmap(base, originX, originY,
                    Math.max(1, cropWidth), Math.max(1, cropHeight))
                    .copy(Bitmap.Config.ARGB_8888, true);
            Canvas canvas = new Canvas(composed);
            ArrayList<SubsurfaceState> childStack = new ArrayList<>(subsurfaces.values());
            childStack.sort((left, right) -> Integer.compare(left.sequence, right.sequence));
            for (SubsurfaceState child : childStack) {
                if (child.visible && child.aboveParent && child.bitmap != null) {
                    canvas.drawBitmap(child.bitmap, child.x - originX, child.y - originY, null);
                }
            }
            ArrayList<PopupState> stack = new ArrayList<>(popups.values());
            stack.sort((left, right) -> Integer.compare(left.sequence, right.sequence));
            for (PopupState popup : stack) {
                if (popup.visible && popup.bitmap != null) {
                    canvas.drawBitmap(popup.bitmap, popup.x - originX, popup.y - originY, null);
                }
            }
            bitmap = composed;
            Runnable callback = frameCommittedCallback;
            if (callback != null) {
                callback.run();
            }
        }

        private int presentationOriginX() {
            WindowGeometry geometry = windowGeometries.get(xdgSurfaceId);
            int scale = Math.max(1, surfaceBufferScales.getOrDefault(surfaceId, 1));
            return geometry == null ? 0 : Math.max(0, geometry.x * scale);
        }

        private int presentationOriginY() {
            WindowGeometry geometry = windowGeometries.get(xdgSurfaceId);
            int scale = Math.max(1, surfaceBufferScales.getOrDefault(surfaceId, 1));
            return geometry == null ? 0 : Math.max(0, geometry.y * scale);
        }
