        private Bitmap readShmBitmap(int bufferId) throws Exception {
            ShmBufferState buffer = shmBuffers.get(bufferId);
            if (buffer == null) {
                throw new IllegalStateException("child toplevel commit with unknown wl_buffer " + bufferId);
            }
            byte[] rgba = readExactFromFd(buffer.pool.fd, buffer.offset, buffer.stride * buffer.height);
            int[] argb = new int[buffer.width * buffer.height];
            for (int y = 0; y < buffer.height; y++) {
                int row = y * buffer.stride;
                for (int x = 0; x < buffer.width; x++) {
                    int p = row + x * 4;
                    int b = rgba[p] & 0xff;
                    int g = rgba[p + 1] & 0xff;
                    int r = rgba[p + 2] & 0xff;
                    int a = buffer.format == 0 ? rgba[p + 3] & 0xff : 0xff;
                    argb[y * buffer.width + x] = (a << 24) | (r << 16) | (g << 8) | b;
                }
            }
            return Bitmap.createBitmap(argb, buffer.width, buffer.height, Bitmap.Config.ARGB_8888);
        }

