            RawWaylandShmServer server = activeInteractiveServer;
            if (server == null) {
                return true;
            }
            float[] point = mapPointerCoordinates(framePreview, server, event.getX(), event.getY());
            boolean mouse = (event.getSource() & android.view.InputDevice.SOURCE_MOUSE)
                    == android.view.InputDevice.SOURCE_MOUSE;
            int action = event.getActionMasked();
            if (mouse) {
                server.handleAndroidMotionEvent(action, point[0], point[1], event.getEventTime());
                return true;
            }
            if (action == MotionEvent.ACTION_DOWN) {
                touchDownX = point[0];
                touchDownY = point[1];
                touchLastY = point[1];
                touchScrolling = false;
                return true;
            }
            if (action == MotionEvent.ACTION_MOVE) {
                float threshold = 12f * getResources().getDisplayMetrics().density;
                if (!touchScrolling && (Math.abs(point[0] - touchDownX) > threshold
                        || Math.abs(point[1] - touchDownY) > threshold)) {
                    touchScrolling = true;
                }
                if (touchScrolling) {
                    float distance = touchLastY - point[1];
                    touchLastY = point[1];
                    if (Math.abs(distance) >= 1f) {
                        server.handleAndroidScrollEvent(point[0], point[1],
                                distance / 48f, event.getEventTime());
                    }
                }
                return true;
            }
            if (action == MotionEvent.ACTION_UP) {
                if (!touchScrolling) {
                    server.handleAndroidMotionEvent(MotionEvent.ACTION_DOWN,
                            point[0], point[1], event.getEventTime());
                    server.handleAndroidMotionEvent(MotionEvent.ACTION_UP,
                            point[0], point[1], event.getEventTime() + 1);
                }
                touchScrolling = false;
                return true;
            }
            if (action == MotionEvent.ACTION_CANCEL) {
                touchScrolling = false;
                return true;
            }
            return true;
        });
