        private void layoutPopup(PopupState popup) {
            float pixelsPerLogical = outputScale;
            int rootX = 0;
            int rootY = 0;
            int logicalX = 0;
            int logicalY = 0;
            PopupState current = popup;
            while (current != null) {
                logicalX += current.configureX;
                logicalY += current.configureY;
                PopupState parent = popupsByXdgSurface.get(current.parentXdgSurfaceId);
                if (parent != null) {
                    current = parent;
                    continue;
                }
                ChildToplevelState rootChild = childToplevelsByXdg.get(current.parentXdgSurfaceId);
                if (rootChild != null) {
                    int rootScale = Math.max(1,
                            surfaceBufferScales.getOrDefault(rootChild.wlSurfaceId, 1));
                    pixelsPerLogical = rootChild.displayWidth
                            / (float) Math.max(1, rootChild.sourceWidth) * rootScale;
                    rootX = rootChild.displayX;
                    rootY = rootChild.displayY;
                }
                break;
            }
            WindowGeometry geometry = windowGeometries.get(popup.xdgSurfaceId);
            int geometryX = geometry == null ? 0 : geometry.x;
            int geometryY = geometry == null ? 0 : geometry.y;
            int popupBufferScale = Math.max(1,
                    surfaceBufferScales.getOrDefault(popup.wlSurfaceId, 1));
            float bitmapScale = pixelsPerLogical / popupBufferScale;
            popup.pixelsPerLogical = Math.max(0.01f, pixelsPerLogical);
            popup.displayX = rootX + Math.round((logicalX - geometryX) * pixelsPerLogical);
            popup.displayY = rootY + Math.round((logicalY - geometryY) * pixelsPerLogical);
            popup.displayWidth = Math.max(1, Math.round(popup.bitmap.getWidth() * bitmapScale));
            popup.displayHeight = Math.max(1, Math.round(popup.bitmap.getHeight() * bitmapScale));
        }

