        private void constrainPopup(PopupState popup) {
            PositionerState original = popup.positioner;
            popup.applyPositioner(original);
            int parentOffsetX = 0;
            int parentOffsetY = 0;
            int rootParentXdg = popup.parentXdgSurfaceId;
            PopupState parent = popupsByXdgSurface.get(rootParentXdg);
            while (parent != null) {
                parentOffsetX += parent.configureX;
                parentOffsetY += parent.configureY;
                rootParentXdg = parent.parentXdgSurfaceId;
                parent = popupsByXdgSurface.get(rootParentXdg);
            }
            int rootWidth = configureWidth;
            int rootHeight = configureHeight;
            ChildToplevelState rootChild = childToplevelsByXdg.get(rootParentXdg);
            if (rootChild != null && rootChild.displayWidth > 1 && rootChild.displayHeight > 1) {
                int rootScale = Math.max(1,
                        surfaceBufferScales.getOrDefault(rootChild.wlSurfaceId, 1));
                float fit = rootChild.displayWidth / (float) Math.max(1, rootChild.sourceWidth);
                float pixelsPerLogical = Math.max(0.01f, rootScale * fit);
                rootWidth = Math.max(1, Math.round(rootChild.displayWidth / pixelsPerLogical));
                rootHeight = Math.max(1, Math.round(rootChild.displayHeight / pixelsPerLogical));
            }
            int minX = -parentOffsetX;
            int minY = -parentOffsetY;
            int maxX = minX + rootWidth;
            int maxY = minY + rootHeight;
            int adjustment = original.constraintAdjustment;

            if ((popup.configureX < minX || popup.configureX + popup.width > maxX)
                    && (adjustment & 4) != 0) {
                PositionerState flipped = new PositionerState(original);
                flipped.anchor = flipHorizontal(flipped.anchor);
                flipped.gravity = flipHorizontal(flipped.gravity);
                int candidate = positionerX(flipped, popup.width);
                if (overflow(candidate, popup.width, minX, maxX)
                        < overflow(popup.configureX, popup.width, minX, maxX)) {
                    popup.configureX = candidate;
                }
            }
            if ((popup.configureY < minY || popup.configureY + popup.height > maxY)
                    && (adjustment & 8) != 0) {
                PositionerState flipped = new PositionerState(original);
                flipped.anchor = flipVertical(flipped.anchor);
                flipped.gravity = flipVertical(flipped.gravity);
                int candidate = positionerY(flipped, popup.height);
                if (overflow(candidate, popup.height, minY, maxY)
                        < overflow(popup.configureY, popup.height, minY, maxY)) {
                    popup.configureY = candidate;
                }
            }
            if ((adjustment & 1) != 0) {
                popup.configureX = clampPosition(popup.configureX, popup.width, minX, maxX);
            }
            if ((adjustment & 2) != 0) {
